# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, url_for, request, redirect, session, abort
import os

app = Flask(__name__)
# Configure the secret key for your application
app.config['SECRET_KEY'] = 'secret-key' 

@app.route('/login', methods=['POST'])
def do_admin_login():
    if request.form['password'] == 'password':
        session['logged_in'] = True
        return redirect(url_for('success')) # If correct password, go to success page
    else:
        abort(401)  # 401 Unauthorized HTTP status code if incorrect password

@app.route('/success')
def success():
    if not session.get('logged_in'):
        return redirect(url_for('do_admin_login'))   # If user is not logged in, go to login page again
    else:
        return "Logged In"
        
@app.route('/')
def home():
    if not session.get('logged_in'):
        return redirect(url_for('do_admin_login'))   # If user is not logged in, go to login page 
    else:
        return "Hello World"
        
if __name__ == '__main__':
    app.run()